=<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Content Editor</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
:root{
  --color-background-primary:#ffffff;
  --color-background-secondary:#f5f5f4;
  --color-background-tertiary:#e8e8e6;
  --color-background-info:#eff6ff;
  --color-background-success:#f0fdf4;
  --color-background-warning:#fffbeb;
  --color-text-primary:#1a1a1a;
  --color-text-secondary:#6b7280;
  --color-text-tertiary:#9ca3af;
  --color-text-info:#1d4ed8;
  --color-text-success:#166534;
  --color-text-warning:#92400e;
  --color-border-tertiary:rgba(0,0,0,0.1);
  --color-border-secondary:rgba(0,0,0,0.18);
  --color-border-primary:rgba(0,0,0,0.28);
  --color-border-info:#93c5fd;
  --color-border-success:#86efac;
  --color-border-warning:#fcd34d;
  --border-radius-md:8px;
  --border-radius-lg:12px;
  --font-sans:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;
  --font-mono:'Courier New',monospace;
}
@media(prefers-color-scheme:dark){
  :root{
    --color-background-primary:#1c1c1e;
    --color-background-secondary:#2c2c2e;
    --color-background-tertiary:#3a3a3c;
    --color-background-info:#1e3a5f;
    --color-background-success:#14532d;
    --color-background-warning:#451a03;
    --color-text-primary:#f2f2f7;
    --color-text-secondary:#aeaeb2;
    --color-text-tertiary:#636366;
    --color-text-info:#93c5fd;
    --color-text-success:#86efac;
    --color-text-warning:#fcd34d;
    --color-border-tertiary:rgba(255,255,255,0.1);
    --color-border-secondary:rgba(255,255,255,0.18);
    --color-border-primary:rgba(255,255,255,0.28);
    --color-border-info:#1d4ed8;
    --color-border-success:#166534;
    --color-border-warning:#92400e;
  }
}
body{background:var(--color-background-secondary);padding:2rem 1rem;font-family:var(--font-sans);min-height:100vh}
.wrap{max-width:820px;margin:0 auto}
.card{background:var(--color-background-primary);border:0.5px solid var(--color-border-tertiary);border-radius:var(--border-radius-lg);overflow:hidden}
.hdr{padding:1rem 1.25rem;border-bottom:0.5px solid var(--color-border-tertiary);display:flex;align-items:center;gap:10px}
.hdr-icon{width:32px;height:32px;border-radius:var(--border-radius-md);background:var(--color-background-info);display:flex;align-items:center;justify-content:center;flex-shrink:0}
.hdr-icon svg{width:16px;height:16px;stroke:var(--color-text-info);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}
.hdr-title{font-size:15px;font-weight:500;color:var(--color-text-primary)}
.body{padding:1.25rem}
.field-label{font-size:12px;color:var(--color-text-secondary);margin-bottom:6px;font-weight:500}
.draft-box{background:var(--color-background-secondary);border:0.5px solid var(--color-border-tertiary);border-radius:var(--border-radius-md);padding:10px 14px;font-family:var(--font-mono);font-size:13px;color:var(--color-text-primary);margin-bottom:1.25rem}
.collapsible{border:0.5px solid var(--color-border-secondary);border-radius:var(--border-radius-md);margin-bottom:1.25rem;overflow:hidden}
.coll-header{padding:10px 14px;display:flex;justify-content:space-between;align-items:center;cursor:pointer;background:var(--color-background-secondary);user-select:none}
.coll-header:hover{background:var(--color-background-tertiary)}
.coll-title{font-size:13px;font-weight:500;color:var(--color-text-secondary)}
.caret{width:16px;height:16px;stroke:var(--color-text-secondary);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round;transition:transform 0.2s}
.caret.open{transform:rotate(180deg)}
.coll-body{padding:14px;font-size:14px;line-height:1.7;color:var(--color-text-primary);max-height:160px;overflow-y:auto;display:none}
.coll-body.open{display:block}
.editor-wrap{border:0.5px solid var(--color-border-secondary);border-radius:var(--border-radius-md);overflow:hidden;margin-bottom:8px}
.editor-wrap:focus-within{box-shadow:0 0 0 2px var(--color-border-info);border-color:var(--color-border-info)}
textarea{width:100%;min-height:280px;padding:14px;border:none;outline:none;font-size:14px;line-height:1.7;font-family:var(--font-sans);resize:vertical;background:var(--color-background-primary);color:var(--color-text-primary)}
.meta-row{display:flex;justify-content:space-between;align-items:center;margin-bottom:1.25rem;flex-wrap:wrap;gap:8px}
.char-count{font-size:12px;color:var(--color-text-tertiary)}
.qactions{display:flex;gap:8px;flex-wrap:wrap}
.qbtn{font-size:12px;padding:5px 11px;background:var(--color-background-secondary);border:0.5px solid var(--color-border-secondary);border-radius:var(--border-radius-md);cursor:pointer;color:var(--color-text-secondary);font-family:var(--font-sans)}
.qbtn:hover{background:var(--color-background-tertiary);color:var(--color-text-primary)}
.status-bar{padding:10px 14px;border-radius:var(--border-radius-md);font-size:13px;margin-bottom:1.25rem;display:none}
.status-bar.success{background:var(--color-background-success);color:var(--color-text-success);border:0.5px solid var(--color-border-success)}
.status-bar.warning{background:var(--color-background-warning);color:var(--color-text-warning);border:0.5px solid var(--color-border-warning)}
.footer{padding:1rem 1.25rem;border-top:0.5px solid var(--color-border-tertiary);display:flex;gap:10px;background:var(--color-background-secondary)}
.btn-main{flex:1;padding:11px;border-radius:var(--border-radius-md);font-size:14px;font-weight:500;cursor:pointer;border:0.5px solid;font-family:var(--font-sans);display:flex;align-items:center;justify-content:center;gap:7px;transition:opacity 0.15s}
.btn-main:hover{opacity:0.85}
.btn-approve{background:var(--color-background-success);border-color:var(--color-border-success);color:var(--color-text-success)}
.btn-save{background:var(--color-background-info);border-color:var(--color-border-info);color:var(--color-text-info)}
.btn-main svg{width:14px;height:14px;fill:none;stroke:currentColor;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}
@media(max-width:600px){.footer{flex-direction:column}}
</style>
</head>
<body>
<div class="wrap">
  <div class="card">
    <div class="hdr">
      <div class="hdr-icon">
        <svg viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
      </div>
      <span class="hdr-title">Content editor</span>
    </div>

    <div class="body">
      <div class="field-label">Draft ID</div>
      <div class="draft-box" id="draftId">{{ $json.query.id }}</div>

      <div class="field-label">Original content</div>
      <div class="collapsible">
        <div class="coll-header" onclick="toggleOrig()">
          <span class="coll-title">Reference — click to expand</span>
          <svg class="caret" id="caret" viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg>
        </div>
        <div class="coll-body" id="origBody">{{ $json.query.content }}</div>
      </div>

      <div class="field-label">Edit content</div>
      <div class="editor-wrap">
        <textarea id="editor" placeholder="Content will load here automatically…" oninput="updateCount()"></textarea>
      </div>
      <div class="meta-row">
        <div class="qactions">
          <button class="qbtn" onclick="reset()">Reset to original</button>
          <button class="qbtn" onclick="clearAll()">Clear</button>
        </div>
        <span class="char-count" id="cc">0 characters</span>
      </div>

      <div class="status-bar" id="status"></div>
    </div>

    <div class="footer">
      <button class="btn-main btn-approve" onclick="sendData('Approved')">
        <svg viewBox="0 0 24 24"><polyline points="20 6 9 17 4 12"/></svg>
        Approve
      </button>
      <button class="btn-main btn-save" onclick="sendData('Draft')">
        <svg viewBox="0 0 24 24"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>
        Save draft
      </button>
    </div>
  </div>
</div>

<script>
let orig = "";
window.addEventListener('DOMContentLoaded', function(){
  orig = document.getElementById("origBody").innerText.trim();
  document.getElementById("editor").value = orig;
  updateCount();
});
function toggleOrig(){
  document.getElementById("origBody").classList.toggle("open");
  document.getElementById("caret").classList.toggle("open");
}
function updateCount(){
  const n = document.getElementById("editor").value.length;
  document.getElementById("cc").textContent = n.toLocaleString() + " characters";
}
function reset(){
  document.getElementById("editor").value = orig;
  updateCount();
  showStatus("Reset to original.", "success");
}
function clearAll(){
  if(confirm("Clear all content?")){
    document.getElementById("editor").value = "";
    updateCount();
    showStatus("Content cleared.", "warning");
  }
}
function showStatus(msg, type){
  const s = document.getElementById("status");
  s.textContent = msg;
  s.className = "status-bar " + type;
  s.style.display = "block";
  setTimeout(()=>{ s.style.display="none"; }, 3000);
}
function sendData(action){
  const id = document.getElementById("draftId").innerText.trim();
  const content = document.getElementById("editor").value.trim();
  if(!content){ showStatus("Please add content before submitting.", "warning"); return; }
  showStatus("Submitting as " + action + "…", "success");
  setTimeout(()=>{
    window.location.href = "https://automation.lockated.com/webhook-test/linkedin-review?id=" + encodeURIComponent(id) + "&action=" + action + "&content=" + encodeURIComponent(content);
  }, 500);
}
</script>
</body>
</html>
